import{_ as a,o as i,c as o,a0 as d}from"./chunks/framework.Cl79jK2u.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function n(l,e,r,s,c,h){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to Moxie are documented here.</p><h2 id="_0-3-3-2026-03-29" tabindex="-1">[0.3.3] - 2026-03-29 <a class="header-anchor" href="#_0-3-3-2026-03-29" aria-label="Permalink to &quot;[0.3.3] - 2026-03-29&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Preflight backend check before subagent dispatch — fails fast with an actionable error when the target backend CLI is missing or unhealthy, instead of silently retrying a doomed job three times</li><li>Preflight check inside <code>processJob</code> so jobs entering through any path (chat, schedules, recovery) also fail fast; error is delivered to the user as a normal message</li><li>Resource limits to prevent runaway fan-out and schedule abuse, all configurable via <code>config.json</code>: <ul><li><code>max_pending_subagents</code> (default 5) — max concurrent subagent jobs per conversation</li><li><code>max_schedules_per_conv</code> (default 20) — max schedules per conversation</li><li><code>max_jobs_per_minute</code> (default 10) — rate limit on <code>moxie send</code> and subagent dispatch</li><li><code>max_schedule_generation</code> (default 3) — caps schedule→dispatch→schedule recursion cycles</li></ul></li><li>Default backend auto-detected at startup from installed CLIs — checks in preferred order (claude → pi → codex → opencode → gemini → any installed), logs the resolved default; no longer silently defaults to <code>claude</code> on systems where it is not installed</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Exec schedule job failures are now delivered to the user as a warning message (<code>⚠️ Scheduled task failed: …</code>) instead of silently removing the job with no notification</li><li>System prompt now tells the agent not to poll subagent status after dispatch — results arrive automatically via synthesis, eliminating unnecessary <code>moxie subagent list/show</code> calls</li><li>Available backends in the system prompt are now filtered to CLIs actually installed on the system — prevents the agent from attempting to delegate to backends that will fail preflight</li><li>Synthesis prompt now instructs the agent to summarize the result with key findings and outcomes rather than just replying &quot;done&quot;</li><li>Delivery logging hardened — <code>SendChunked</code> logs message IDs, chunk counts, and returns an error when nothing is delivered; <code>DeliverJobResult</code> logs job ID, conversation, result length, and file count</li></ul><h2 id="_0-3-2-2026-03-25" tabindex="-1">[0.3.2] - 2026-03-25 <a class="header-anchor" href="#_0-3-2-2026-03-25" aria-label="Permalink to &quot;[0.3.2] - 2026-03-25&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Block subagent chaining from synthesis turns — prevents runaway loops where a synthesis turn spawns another subagent</li></ul><h2 id="_0-3-1-2026-03-24" tabindex="-1">[0.3.1] - 2026-03-24 <a class="header-anchor" href="#_0-3-1-2026-03-24" aria-label="Permalink to &quot;[0.3.1] - 2026-03-24&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Webex file upload — agents can send files back via <code>&lt;send&gt;</code> tags using multipart upload</li><li>Webex file download — inbound attachments are downloaded with Bearer auth and passed to the agent</li><li>Live activity updates for Webex — status messages are edited in-place via <code>PUT /messages/{id}</code>, matching the Telegram experience</li><li>Verb-aware activity rendering for Webex (Reading files, Running command, Searching)</li></ul><h2 id="_0-3-0-2026-03-24" tabindex="-1">[0.3.0] - 2026-03-24 <a class="header-anchor" href="#_0-3-0-2026-03-24" aria-label="Permalink to &quot;[0.3.0] - 2026-03-24&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Webex transport for 1:1 direct messages — <code>moxie serve --transport webex</code></li><li>Per-sender ACLs via <code>allowed_user_ids</code> and <code>allowed_emails</code></li><li>Bot ID auto-discovery from Webex token</li><li>Webex schedule, subagent, and result delivery support</li><li>Room activity filtering to minimize API polling overhead</li><li>Room type caching to avoid redundant GetRoom calls</li></ul><h2 id="_0-2-9-2026-03-24" tabindex="-1">[0.2.9] - 2026-03-24 <a class="header-anchor" href="#_0-2-9-2026-03-24" aria-label="Permalink to &quot;[0.2.9] - 2026-03-24&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>/think</code> now passes through any value to the backend instead of validating against a hardcoded list — backends report invalid levels, allowing agents to self-heal</li><li>Bump oneagent to v0.11.13 (improved error handling, backend-side thinking validation)</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>moxie service install</code> now captures the user&#39;s actual PATH at install time instead of a hardcoded fallback — fixes backends like <code>pi</code> not being found when running as a service</li><li><code>moxie service install</code> and <code>moxie service start/stop/restart</code> now detect missing systemd user sessions and suggest <code>sudo loginctl enable-linger &lt;user&gt;</code> instead of showing opaque &quot;exit status 1&quot; or &quot;No medium found&quot; errors</li></ul><h2 id="_0-2-8-2026-03-24" tabindex="-1">[0.2.8] - 2026-03-24 <a class="header-anchor" href="#_0-2-8-2026-03-24" aria-label="Permalink to &quot;[0.2.8] - 2026-03-24&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Subagent jobs now dispatch in parallel — previously ran sequentially, causing jobs to appear dropped when multiple subagents were dispatched simultaneously</li><li>In-flight tracking prevents ticker from re-dispatching jobs already being processed</li><li>Stop retrying delivered jobs in the hot loop — removed &quot;delivered&quot; from retry predicate to fix zombie retry loops (observed running for 2.5+ hours)</li><li>Replace PID-based serve lock with flock for race-free mutual exclusion (fixes TOCTOU race on PID recycling)</li><li>Robust PATH propagation for launchd schedule plists — detects minimal PATH and falls back to reading from the main service plist</li></ul><h2 id="_0-2-7-2026-03-23" tabindex="-1">[0.2.7] - 2026-03-23 <a class="header-anchor" href="#_0-2-7-2026-03-23" aria-label="Permalink to &quot;[0.2.7] - 2026-03-23&quot;">​</a></h2><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Exec schedule jobs now use <code>bash -l</code> instead of <code>sh</code>, loading login profile PATH so tools like <code>claude</code> and <code>gog</code> are found on macOS</li></ul><h2 id="_0-2-6-2026-03-23" tabindex="-1">[0.2.6] - 2026-03-23 <a class="header-anchor" href="#_0-2-6-2026-03-23" aria-label="Permalink to &quot;[0.2.6] - 2026-03-23&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Exec schedule action (<code>--action exec</code>) for command-based notifications — runs a shell command and delivers stdout to the conversation, staying silent when the script produces no output</li><li>Platform and shell detection injected into agent system prompt for OS-appropriate script generation</li></ul><h2 id="_0-2-5-2026-03-23" tabindex="-1">[0.2.5] - 2026-03-23 <a class="header-anchor" href="#_0-2-5-2026-03-23" aria-label="Permalink to &quot;[0.2.5] - 2026-03-23&quot;">​</a></h2><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Orphaned delivered schedule jobs are now dropped instead of retrying forever when their schedule has been removed</li><li>Cross-process file lock (<code>flock</code>) for schedule store mutations prevents concurrent write corruption between <code>moxie serve</code> and <code>moxie schedule fire</code></li><li>macOS serve CWD resolution prefers logical <code>$PWD</code> over physical path to avoid <code>/private/var</code> symlink confusion</li></ul><h2 id="_0-2-4-2026-03-23" tabindex="-1">[0.2.4] - 2026-03-23 <a class="header-anchor" href="#_0-2-4-2026-03-23" aria-label="Permalink to &quot;[0.2.4] - 2026-03-23&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>System prompts now mention <code>moxie service</code> and warn against running <code>moxie serve</code> directly to prevent duplicate processes</li></ul><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>macOS launchd one-shot cleanup: <code>launchctl bootout</code> failure no longer prevents plist removal and schedule store cleanup when the fire process is the launchd job itself</li></ul><h2 id="_0-2-3-2026-03-23" tabindex="-1">[0.2.3] - 2026-03-23 <a class="header-anchor" href="#_0-2-3-2026-03-23" aria-label="Permalink to &quot;[0.2.3] - 2026-03-23&quot;">​</a></h2><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Synthesis prompt rewritten for natural conversation flow instead of formal report-style responses</li><li>Documented <code>moxie subagent list/show/cancel</code> commands and sequential task continuation in guide and CLI reference</li></ul><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>macOS launchd one-shot schedules: <code>--in</code> durations now round up to next whole minute instead of falling back to in-process</li><li><code>schedule rm</code> no longer blocked by stale <code>RunningJobID</code> when the referenced job no longer exists</li><li>Schedule store writes are now atomic (temp file + rename) to prevent JSON corruption from concurrent writers</li><li>Schedule store reads fall back to <code>.bak</code> copy when primary JSON is corrupt</li></ul><h2 id="_0-2-2-2026-03-23" tabindex="-1">[0.2.2] - 2026-03-23 <a class="header-anchor" href="#_0-2-2-2026-03-23" aria-label="Permalink to &quot;[0.2.2] - 2026-03-23&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Synthesis continuation loop hardened per code review: model now passed through to synthesis prompt, continuation trigger tightened to require explicit sequential requests, result marked as untrusted to mitigate prompt injection</li></ul><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Duplicate thread messages caused by concurrent writers (synthesis and main conversation) — bumped oneagent to v0.11.12 with turn-level dedup</li><li>Added pidfile guard to <code>moxie serve</code> to prevent duplicate instances from running simultaneously</li></ul><h2 id="_0-2-1-2026-03-22" tabindex="-1">[0.2.1] - 2026-03-22 <a class="header-anchor" href="#_0-2-1-2026-03-22" aria-label="Permalink to &quot;[0.2.1] - 2026-03-22&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Schedule abstraction</strong> — canonical trigger model, <code>--every</code> interval UX, <code>fire</code> execution entrypoint, backend reconciliation layer, and portable cron normalization</li><li><strong>macOS launchd schedule backend</strong> with one-shot year-precision guard and fallback-reason preservation</li><li><strong>Windows Task Scheduler schedule backend</strong> with tolerant delete handling on cleanup</li><li><strong><code>moxie subagent list</code></strong>, <strong><code>show</code></strong>, and <strong><code>cancel</code></strong> subcommands for inspecting and managing background work</li><li><strong>Synthesis continuation loop</strong> — when a user requests multiple sequential tasks, the synthesis step now automatically dispatches the next task instead of just summarizing and stopping</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Progress stall timeout disabled by default to avoid false positives on long-running subagent tasks</li><li>Docs refreshed: home quick-start, service notes, Windows scheduler status, schedule rollout cleanup</li></ul><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Hardened synthesis continuation loop to avoid duplicate dispatches and handle edge cases per code review</li></ul><h2 id="_0-2-0-2026-03-22" tabindex="-1">[0.2.0] - 2026-03-22 <a class="header-anchor" href="#_0-2-0-2026-03-22" aria-label="Permalink to &quot;[0.2.0] - 2026-03-22&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Supervised subagent execution with config-driven retry/backoff, stall detection, progress timeouts, and terminal escalation after repeated failure</li><li>Persisted subagent supervision state for attempts, active run IDs, and last-seen event/progress timestamps</li><li>Blocking subagent failure recovery so nested parent runs are unblocked immediately instead of hanging until timeout</li></ul><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Moxie now consumes <code>oneagent v0.11.11</code> telemetry with per-run IDs, timestamps, start events, and heartbeats</li><li>Subagent dispatch now serializes work by backend thread ID when available, preventing same-thread races across subagent and synthesis paths</li><li>Nested <code>moxie subagent</code> calls now prefer the immediate parent job via <code>MOXIE_JOB_ID</code> and block until child completion</li><li>Synthesis is queued instead of running inline on the parent thread</li></ul><h3 id="fixed-10" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-10" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Stale subagent attempt events/results no longer overwrite the active attempt outcome</li><li>Hanging or discarded blocking child jobs now surface deterministic failure results back to their waiting parent</li></ul><h2 id="_0-1-10-2026-03-21" tabindex="-1">[0.1.10] - 2026-03-21 <a class="header-anchor" href="#_0-1-10-2026-03-21" aria-label="Permalink to &quot;[0.1.10] - 2026-03-21&quot;">​</a></h2><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Bumped <code>oneagent</code> to <code>v0.11.10</code></li></ul><h3 id="fixed-11" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-11" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Codex subagents now inherit the backend-agnostic <code>oneagent</code> template fix for empty inline assignment args, preventing <code>exit status 1</code> when thinking is unset</li></ul><h2 id="_0-1-9-2026-03-21" tabindex="-1">[0.1.9] - 2026-03-21 <a class="header-anchor" href="#_0-1-9-2026-03-21" aria-label="Permalink to &quot;[0.1.9] - 2026-03-21&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Configurable <code>default_cwd</code> with platform-specific managed workspace defaults for Linux and macOS</li></ul><h3 id="changed-7" tabindex="-1">Changed <a class="header-anchor" href="#changed-7" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie init</code> now prompts for a default workspace and can install the service against that configured default</li><li><code>moxie serve</code> now prefers an explicit <code>--cwd</code>, then the current shell directory, then <code>default_cwd</code>, then the platform workspace default</li><li><code>moxie service install</code> now uses the service manager working directory instead of passing <code>--cwd</code> to <code>moxie serve</code></li><li>README and docs now emphasize the service-first setup flow and remove internal <code>oneagent</code>/<code>oa list</code> references from user-facing guidance</li></ul><h3 id="fixed-12" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-12" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>User-facing docs now match actual <code>/cwd</code> behavior for named workspaces</li></ul><h2 id="_0-1-8-2026-03-22" tabindex="-1">[0.1.8] - 2026-03-22 <a class="header-anchor" href="#_0-1-8-2026-03-22" aria-label="Permalink to &quot;[0.1.8] - 2026-03-22&quot;">​</a></h2><h3 id="fixed-13" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-13" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>LaunchAgent installs now capture <code>PATH</code> and <code>HOME</code> so backend CLIs remain available when Moxie runs under <code>launchd</code></li></ul><h2 id="_0-1-7-2026-03-21" tabindex="-1">[0.1.7] - 2026-03-21 <a class="header-anchor" href="#_0-1-7-2026-03-21" aria-label="Permalink to &quot;[0.1.7] - 2026-03-21&quot;">​</a></h2><h3 id="fixed-14" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-14" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>LaunchAgent installs now prefer the stable <code>moxie</code> path from <code>PATH</code> instead of a versioned Homebrew Cellar path</li></ul><h3 id="changed-8" tabindex="-1">Changed <a class="header-anchor" href="#changed-8" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie service install</code>, <code>start</code>, <code>stop</code>, <code>uninstall</code>, <code>restart</code>, and <code>reload</code> now print explicit confirmation messages on success</li></ul><h2 id="_0-1-6-2026-03-21" tabindex="-1">[0.1.6] - 2026-03-21 <a class="header-anchor" href="#_0-1-6-2026-03-21" aria-label="Permalink to &quot;[0.1.6] - 2026-03-21&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>moxie service install</code> and <code>moxie service uninstall</code> for native service definition management</li><li>Optional service install/start flow during <code>moxie init</code></li></ul><h3 id="changed-9" tabindex="-1">Changed <a class="header-anchor" href="#changed-9" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie init</code> can now collect a default service working directory when installing a background service</li></ul><h2 id="_0-1-5-2026-03-21" tabindex="-1">[0.1.5] - 2026-03-21 <a class="header-anchor" href="#_0-1-5-2026-03-21" aria-label="Permalink to &quot;[0.1.5] - 2026-03-21&quot;">​</a></h2><h3 id="fixed-15" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-15" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Windows cross-build compatibility for the macOS launchd reload path</li></ul><h2 id="_0-1-4-2026-03-21" tabindex="-1">[0.1.4] - 2026-03-21 <a class="header-anchor" href="#_0-1-4-2026-03-21" aria-label="Permalink to &quot;[0.1.4] - 2026-03-21&quot;">​</a></h2><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>macOS <code>launchd</code> support for <code>moxie service start|stop|restart|reload|status</code></li><li>LaunchAgent documentation for <code>~/Library/LaunchAgents/io.github.1broseidon.moxie.plist</code></li></ul><h3 id="changed-10" tabindex="-1">Changed <a class="header-anchor" href="#changed-10" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>macOS service control now follows the per-user LaunchAgent model instead of failing through <code>systemctl</code></li></ul><h2 id="_0-1-3-2026-03-21" tabindex="-1">[0.1.3] - 2026-03-21 <a class="header-anchor" href="#_0-1-3-2026-03-21" aria-label="Permalink to &quot;[0.1.3] - 2026-03-21&quot;">​</a></h2><h3 id="changed-11" tabindex="-1">Changed <a class="header-anchor" href="#changed-11" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Service lifecycle commands now live under <code>moxie service ...</code> instead of top-level <code>moxie start|stop|restart|reload|status</code></li><li>Non-Linux platforms now get a clear service-manager error instead of attempting to invoke <code>systemctl</code></li></ul><h2 id="_0-1-2-2026-03-21" tabindex="-1">[0.1.2] - 2026-03-21 <a class="header-anchor" href="#_0-1-2-2026-03-21" aria-label="Permalink to &quot;[0.1.2] - 2026-03-21&quot;">​</a></h2><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Top-level <code>moxie start</code>, <code>stop</code>, <code>restart</code>, <code>reload</code>, and <code>status</code> commands for user service control</li><li>In-process <code>SIGHUP</code> reload support for <code>moxie serve</code> so config and backend definitions can be reloaded without exiting the process</li></ul><h3 id="changed-12" tabindex="-1">Changed <a class="header-anchor" href="#changed-12" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Backend prompts now frame Claude, Codex, and other backends as operating on behalf of Moxie</li><li>Capability descriptions are guided toward local CLI behavior and user-facing Moxie features instead of harness-centric language</li><li><code>poll</code> and <code>cursor</code> are now documented as operator/debug commands instead of primary user commands</li></ul><h3 id="fixed-16" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-16" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Release workflow can now be manually dispatched for an existing tag</li><li>Homebrew tap publishing path was validated and backfilled</li><li>Prompt injection tests now allow the backend identity suffix added to system prompts</li></ul><h2 id="_0-1-0-2026-03-20" tabindex="-1">[0.1.0] - 2026-03-20 <a class="header-anchor" href="#_0-1-0-2026-03-20" aria-label="Permalink to &quot;[0.1.0] - 2026-03-20&quot;">​</a></h2><p>Initial public release.</p><h3 id="added-10" tabindex="-1">Added <a class="header-anchor" href="#added-10" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Telegram transport with long polling, HTML formatting, photo handling, and file attachments</li><li>Slack transport with Socket Mode, mrkdwn formatting, and thread support</li><li>Multi-backend dispatch via oneagent (Claude, Codex, Gemini, Pi, OpenCode)</li><li><code>/model</code> command to switch backends and models per conversation</li><li><code>/think</code> command for reasoning effort control (low/medium/high)</li><li><code>/cwd</code> command with named workspaces</li><li><code>/new</code> and <code>/threads</code> for thread management</li><li><code>/compact</code> for thread compaction</li><li>Schedules with one-shot (<code>--in</code>, <code>--at</code>) and recurring (<code>--cron</code>) triggers</li><li>Subagent delegation with synthesis back to parent conversation</li><li>Paragraph-aware message chunking for long responses</li><li>Activity status messages during dispatch</li><li>Job persistence and recovery across restarts</li><li>systemd service support</li></ul>',109)])])}const g=a(t,[["render",n]]);export{m as __pageData,g as default};
